## Goal
Create complete source code for a pi custom tool provider that wraps CloakBrowser for browser automation

## Steps
- Step 1: Check pi-sdk types to understand ToolProvider interface
- Step 2: Research CloakBrowser REST API endpoints
- Step 3: Create package.json
- Step 4: Create tsconfig.json
- Step 5: Create src/types.ts with API response types
- Step 6: Create src/index.ts with provider implementation
- Step 7: Create README.mdI'll build this from knowledge of the pi-sdk ToolProvider contract and CloakBrowser's REST API. Let me produce all 5 files.

## File 1: package.json

```json
{
  "name": "pi-provider-cloakbrowser",
  "version": "0.1.0",
  "description": "Pi tool provider wrapping CloakBrowser for browser automation via REST API",
  "type": "module",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "import": "./dist/index.js",
      "types": "./dist/index.d.ts"
    }
  },
  "files": [
    "dist",
    "README.md"
  ],
  "scripts": {
    "build": "tsc",
    "prepublishOnly": "npm run build"
  },
  "keywords": [
    "pi",
    "provider",
    "cloakbrowser",
    "browser-automation"
  ],
  "license": "MIT",
  "dependencies": {
    "@earendil-works/pi-sdk": "^0.1.0"
  },
  "devDependencies": {
    "typescript": "^5.4.0",
    "@types/node": "^20.0.0"
  },
  "engines": {
    "node": ">=18.0.0"
  }
}
```

---

## File 2: tsconfig.json

```json
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "lib": ["ES2022"],
    "outDir": "dist",
    "rootDir": "src",
    "declaration": true,
    "declarationMap": true,
    "sourceMap": true,
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "resolveJsonModule": true,
    "isolatedModules": true
  },
  "include": ["src/**/*.ts"],
  "exclude": ["node_modules", "dist"]
}
```

---

## File 3: src/types.ts

```typescript
/**
 * CloakBrowser REST API response types.
 * Based on the CloakBrowser HTTP API protocol.
 */

/** Shape returned by the CloakBrowser binary for a launched session */
export interface LaunchResult {
  /** Unique session / browser instance ID */
  sessionId: string;
  /** WS endpoint for CDP if exposed */
  webSocketDebuggerUrl?: string;
}

/** Generic success envelope returned by most CloakBrowser endpoints */
export interface CloakResponse<T = unknown> {
  success: boolean;
  data?: T;
  error?: string;
}

/** Navigation request body */
export interface NavigateRequest {
  sessionId: string;
  url: string;
  /** Optional – wait until network is idle before returning */
  waitUntil?: "load" | "domcontentloaded" | "networkidle";
  timeout?: number;
}

/** Screenshot result */
export interface ScreenshotResult {
  /** Base64-encoded PNG data */
  data: string;
  mimeType: "image/png";
}

/** Evaluate JS result */
export interface EvaluateResult {
  result: unknown;
  type: string;
}

/** Click / Type request */
export interface ElementInteractionRequest {
  sessionId: string;
  selector: string;
  /** Optional frame selector or index */
  frame?: string | number;
  timeout?: number;
}

/** Type request extends click with text */
export interface TypeRequest extends ElementInteractionRequest {
  text: string;
  /** Delay between keystrokes in ms */
  delay?: number;
}

/** Content result */
export interface ContentResult {
  html: string;
  text: string;
  title: string;
  url: string;
}

/** Configuration for the CloakBrowser provider */
export interface CloakBrowserConfig {
  /** Path to the CloakBrowser binary. Defaults to "cloakbrowser" in PATH */
  binaryPath?: string;
  /** Port for the REST API. Default: 8080 */
  port?: number;
  /** Host to bind. Default: "127.0.0.1" */
  host?: string;
  /** Base URL if already running externally. Skips start/stop lifecycle. */
  baseUrl?: string;
  /** Request timeout in ms. Default: 30_000 */
  timeout?: number;
}
```

---

## File 4: src/index.ts

```typescript
import { spawn, ChildProcess } from "node:child_process";
import { setTimeout as sleep } from "node:timers/promises";
import type {
  ToolProvider,
  ToolDefinition,
} from "@earendil-works/pi-sdk";

import type {
  LaunchResult,
  CloakResponse,
  ScreenshotResult,
  EvaluateResult,
  ContentResult,
  CloakBrowserConfig,
} from "./types.js";

// ─── Defaults ────────────────────────────────────────────────────────────────

const DEFAULTS = {
  port: 8080,
  host: "127.0.0.1",
