import { spawn, ChildProcess } from "node:child_process";
import { setTimeout as sleep } from "node:timers/promises";
import type {
  ToolProvider,
  ToolDefinition,
} from "@earendil-works/pi-sdk";

import type {
  LaunchResult,
  CloakResponse,
  ScreenshotResult,
  EvaluateResult,
  ContentResult,
  CloakBrowserConfig,
} from "./types.js";

const DEFAULTS = {
  port: 8080,
  host: "127.0.0.1",
  timeout: 30_000,
  binaryPath: "cloakbrowser",
};

const TOOLS: ToolDefinition[] = [
  {
    name: "browser_launch",
    description: "Launch a new browser instance and return a session ID",
    inputSchema: {
      type: "object",
      properties: {
        headless: { type: "boolean", description: "Run in headless mode (default: true)" },
        proxy: { type: "string", description: "Proxy server URL" },
        viewport: {
          type: "object", description: "Viewport size {width, height}",
          properties: { width: { type: "number" }, height: { type: "number" } },
        },
        userAgent: { type: "string", description: "Custom User-Agent" },
      },
    },
  },
  {
    name: "browser_navigate",
    description: "Navigate the browser to a URL",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
        url: { type: "string", description: "URL to navigate to" },
        waitUntil: {
          type: "string", enum: ["load", "domcontentloaded", "networkidle"],
          description: "When to consider navigation complete",
        },
        timeout: { type: "number", description: "Navigation timeout in ms" },
      },
      required: ["sessionId", "url"],
    },
  },
  {
    name: "browser_screenshot",
    description: "Take a screenshot of the current page or a specific element",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
        selector: { type: "string", description: "CSS selector for a specific element" },
        fullPage: { type: "boolean", description: "Capture full scrollable page" },
        format: { type: "string", enum: ["png", "jpeg"], description: "Image format" },
      },
      required: ["sessionId"],
    },
  },
  {
    name: "browser_evaluate",
    description: "Execute JavaScript in the browser page context",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
        script: { type: "string", description: "JavaScript code to execute" },
      },
      required: ["sessionId", "script"],
    },
  },
  {
    name: "browser_click",
    description: "Click an element on the page identified by CSS selector",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
        selector: { type: "string", description: "CSS selector of element to click" },
        timeout: { type: "number", description: "Wait timeout for element in ms" },
      },
      required: ["sessionId", "selector"],
    },
  },
  {
    name: "browser_type",
    description: "Type text into an input element identified by CSS selector",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
        selector: { type: "string", description: "CSS selector of target element" },
        text: { type: "string", description: "Text to type" },
        delay: { type: "number", description: "Delay between keystrokes in ms" },
        clear: { type: "boolean", description: "Clear the field before typing" },
      },
      required: ["sessionId", "selector", "text"],
    },
  },
  {
    name: "browser_get_content",
    description: "Get page HTML, text content, title and URL",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID" },
      },
      required: ["sessionId"],
    },
  },
  {
    name: "browser_close",
    description: "Close a browser session and release resources",
    inputSchema: {
      type: "object",
      properties: {
        sessionId: { type: "string", description: "Browser session ID to close" },
      },
      required: ["sessionId"],
    },
  },
];

class CloakBrowserProvider implements ToolProvider {
  name = "cloakbrowser";
  version = "0.1.0";
  tools = TOOLS;

  private proc: ChildProcess | null = null;
  private config: Required<CloakBrowserConfig>;
  private running = false;

  constructor(config: CloakBrowserConfig = {}) {
    this.config = {
      binaryPath: config.binaryPath ?? DEFAULTS.binaryPath,
      port: config.port ?? DEFAULTS.port,
      host: config.host ?? DEFAULTS.host,
      baseUrl: config.baseUrl ?? "",
      timeout: config.timeout ?? DEFAULTS.timeout,
    };
  }

  private get apiBase(): string {
    return this.config.baseUrl || `http://${this.config.host}:${this.config.port}`;
  }

  async start(): Promise<void> {
    if (this.config.baseUrl) {
      this.running = true;
      return;
    }

    const { binaryPath, port, host } = this.config;
    this.proc = spawn(binaryPath, ["--port", String(port), "--host", host], {
      stdio: ["ignore", "pipe", "pipe"],
      detached: false,
    });

    this.proc.on("error", (err) => {
      throw new Error(`Failed to start CloakBrowser: ${err.message}`);
    });

    this.proc.on("exit", (code) => {
      this.running = false;
      if (code !== 0 && code !== null) {
        console.warn(`[cloakbrowser] process exited with code ${code}`);
      }
    });

    await this.waitForReady();
    this.running = true;
  }

  async stop(): Promise<void> {
    if (this.proc && !this.proc.killed) {
      try { await this.apiPost("/shutdown", {}); } catch {}
      this.proc.kill("SIGTERM");
      const killer = new Promise<void>((_, reject) =>
        setTimeout(() => reject(new Error("timeout")), 5_000)
      );
      const exited = new Promise<void>((resolve) => {
        this.proc!.on("exit", () => resolve());
      });
      try { await Promise.race([exited, killer]); }
      catch { this.proc.kill("SIGKILL"); await exited.catch(() => {}); }
    }
    this.proc = null;
    this.running = false;
  }

  async callTool(name: string, args: Record<string, unknown>) {
    if (!this.running && name !== "browser_launch") {
      throw new Error("CloakBrowser not running. Call browser_launch first.");
    }
    try {
      switch (name) {
        case "browser_launch": return await this.handleLaunch(args);
        case "browser_navigate": return await this.handleNavigate(args);
        case "browser_screenshot": return await this.handleScreenshot(args);
        case "browser_evaluate": return await this.handleEvaluate(args);
        case "browser_click": return await this.handleClick(args);
        case "browser_type": return await this.handleType(args);
        case "browser_get_content": return await this.handleGetContent(args);
        case "browser_close": return await this.handleClose(args);
        default: throw new Error(`Unknown tool: ${name}`);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      return { content: [{ type: "text", text: `Error: ${message}` }] };
    }
  }

  private async handleLaunch(args: Record<string, unknown>) {
    const body: Record<string, unknown> = {};
    if (args.headless !== undefined) body.headless = args.headless;
    if (args.proxy) body.proxy = args.proxy;
    if (args.viewport) body.viewport = args.viewport;
    if (args.userAgent) body.userAgent = args.userAgent;
    const res = await this.apiPost<LaunchResult>("/launch", body);
    return { content: [{ type: "text", text: JSON.stringify(
      { sessionId: res.sessionId, webSocketDebuggerUrl: res.webSocketDebuggerUrl }, null, 2
    ) }] };
  }

  private async handleNavigate(args: Record<string, unknown>) {
    await this.apiPost("/navigate", {
      sessionId: args.sessionId, url: args.url,
      waitUntil: args.waitUntil ?? "load",
      timeout: args.timeout ?? this.config.timeout,
    });
    return { content: [{ type: "text", text: `Navigated to ${args.url}` }] };
  }

  private async handleScreenshot(args: Record<string, unknown>) {
    const res = await this.apiPost<{ data: string }>("/screenshot", {
      sessionId: args.sessionId, selector: args.selector,
      fullPage: args.fullPage ?? false, format: args.format ?? "png",
    });
    return {
      content: [
        { type: "text", text: `Screenshot taken (${res.data.length} bytes base64)` },
        { type: "image", data: res.data, mimeType: args.format === "jpeg" ? "image/jpeg" : "image/png" },
      ],
    };
  }

  private async handleEvaluate(args: Record<string, unknown>) {
    const res = await this.apiPost<EvaluateResult>("/evaluate", {
      sessionId: args.sessionId, script: args.script,
    });
    return { content: [{ type: "text", text:
      typeof res.result === "string" ? res.result : JSON.stringify(res.result, null, 2)
    }] };
  }

  private async handleClick(args: Record<string, unknown>) {
    await this.apiPost("/click", {
      sessionId: args.sessionId, selector: args.selector,
      timeout: args.timeout ?? this.config.timeout,
    });
    return { content: [{ type: "text", text: `Clicked element: ${args.selector}` }] };
  }

  private async handleType(args: Record<string, unknown>) {
    await this.apiPost("/type", {
      sessionId: args.sessionId, selector: args.selector,
      text: args.text, delay: args.delay ?? 0, clear: args.clear ?? false,
    });
    return { content: [{ type: "text", text: `Typed "${args.text}" into ${args.selector}` }] };
  }

  private async handleGetContent(args: Record<string, unknown>) {
    const res = await this.apiPost<ContentResult>("/content", { sessionId: args.sessionId });
    return { content: [
      { type: "text", text: JSON.stringify({ title: res.title, url: res.url, text: res.text }, null, 2) },
      { type: "text", text: `\n--- HTML (${res.html.length} chars) ---\n${
        res.html.slice(0, 10_000)
      }${res.html.length > 10_000 ? "\n... (truncated)" : ""}` },
    ]};
  }

  private async handleClose(args: Record<string, unknown>) {
    await this.apiPost("/close", { sessionId: args.sessionId });
    return { content: [{ type: "text", text: `Session ${args.sessionId} closed` }] };
  }

  private async apiPost<T = unknown>(path: string, body: Record<string, unknown>): Promise<T> {
    const url = `${this.apiBase}/v1${path}`;
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), this.config.timeout);
    try {
      const res = await fetch(url, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body), signal: ctrl.signal,
      });
      if (!res.ok) {
        const text = await res.text().catch(() => "");
        throw new Error(`CloakBrowser API ${res.status} on ${path}: ${text || res.statusText}`);
      }
      const json = (await res.json()) as CloakResponse<T>;
      if (!json.success) throw new Error(`CloakBrowser error on ${path}: ${json.error ?? "unknown"}`);
      return json.data as T;
    } finally {
      clearTimeout(timer);
    }
  }

  private async waitForReady(): Promise<void> {
    const deadline = Date.now() + 15_000;
    while (Date.now() < deadline) {
      try {
        const res = await fetch(`${this.apiBase}/health`, { signal: AbortSignal.timeout(1_000) });
        if (res.ok) return;
      } catch {}
      await sleep(300);
    }
    throw new Error(`CloakBrowser did not become ready within 15s on ${this.apiBase}`);
  }
}

export function createProvider(config?: CloakBrowserConfig): ToolProvider {
  return new CloakBrowserProvider(config);
}
