  { name: "browser_click", description: "Click an element by CSS selector", inputSchema: { type: "object", properties: { sessionId: { type: "string" }, selector: { type: "string" }, timeout: { type: "number" } }, required: ["sessionId", "selector"] } },
  { name: "browser_type", description: "Type text into an input element", inputSchema: { type: "object", properties: { sessionId: { type: "string" }, selector: { type: "string" }, text: { type: "string" }, delay: { type: "number" }, clear: { type: "boolean" } }, required: ["sessionId", "selector", "text"] } },
  { name: "browser_get_content", description: "Get page HTML, text content, title and URL", inputSchema: { type: "object", properties: { sessionId: { type: "string" } }, required: ["sessionId"] } },
  { name: "browser_close", description: "Close a browser session", inputSchema: { type: "object", properties: { sessionId: { type: "string" } }, required: ["sessionId"] } },
