  private async handleScreenshot(args: Record<string, unknown>) {
    const res = await this.apiPost<{ data: string }>("/screenshot", { sessionId: args.sessionId, selector: args.selector, fullPage: args.fullPage ?? false, format: args.format ?? "png" });
